import{_ as i,o as a,c as e,a9 as r}from"./chunks/framework.STMWz9Nm.js";const u=JSON.parse('{"title":"实战思路与常见问题","description":"","frontmatter":{},"headers":[],"relativePath":"语言/java/12-Netty学习/06-实战思路与常见问题.md","filePath":"语言/java/12-Netty学习/06-实战思路与常见问题.md","lastUpdated":1777177198000}'),h={name:"语言/java/12-Netty学习/06-实战思路与常见问题.md"};function t(n,l,p,d,o,s){return a(),e("div",null,[...l[0]||(l[0]=[r('<h1 id="实战思路与常见问题" tabindex="-1">实战思路与常见问题 <a class="header-anchor" href="#实战思路与常见问题" aria-label="Permalink to “实战思路与常见问题”">​</a></h1><h2 id="_1-这是什么" tabindex="-1">1. 这是什么 <a class="header-anchor" href="#_1-这是什么" aria-label="Permalink to “1. 这是什么”">​</a></h2><p>前面几篇内容如果你都看了，会发现 Netty 的知识点已经不少：</p><ul><li>架构与事件驱动</li><li>ByteBuf 与编解码</li><li>Channel 与 Pipeline</li><li>粘包拆包与协议设计</li><li>线程模型与性能优化</li></ul><p>但很多人真正卡住的地方不在“知识点不会背”，而在：</p><ul><li>真到项目里，不知道从哪开始设计</li><li>demo 能跑，线上一上量就出问题</li><li>遇到断连、超时、堆积、内存异常时没有排查思路</li></ul><p>所以这一篇的作用，不是再加一堆新名词，而是把前面那些知识串成：</p><ul><li><strong>接近实战的设计思路</strong></li><li><strong>常见线上问题的排查框架</strong></li></ul><p>如果先只记一句话，可以记成：</p><blockquote><p><strong>Netty 项目能不能做稳，不只看代码能不能收发消息，而要同时设计好协议、连接、线程、资源和故障处理。</strong></p></blockquote><hr><h2 id="_2-为什么重要" tabindex="-1">2. 为什么重要 <a class="header-anchor" href="#_2-为什么重要" aria-label="Permalink to “2. 为什么重要”">​</a></h2><p>很多 Netty 入门项目的问题都很像：</p><ul><li>能连上</li><li>能发消息</li><li>能收到响应</li></ul><p>于是就以为“已经做完了”。</p><p>但真实项目里，后面很快会遇到这些问题：</p><ul><li>客户端断线重连怎么办</li><li>空闲连接要不要保活</li><li>心跳多久发一次</li><li>消息积压时怎么办</li><li>下游慢了会不会把整条链路拖死</li><li>写出过快时会不会内存涨</li><li>某类异常是关连接还是重试</li></ul><p>这些问题解决不好，demo 再漂亮也离线上可用很远。</p><p>所以这一章的核心不是“把 Netty 用起来”，而是：</p><blockquote><p><strong>把一个网络服务从“能跑”往“能长期稳定运行”推进。</strong></p></blockquote><hr><h2 id="_3-做-netty-实战-先从-4-个层面一起想" tabindex="-1">3. 做 Netty 实战，先从 4 个层面一起想 <a class="header-anchor" href="#_3-做-netty-实战-先从-4-个层面一起想" aria-label="Permalink to “3. 做 Netty 实战，先从 4 个层面一起想”">​</a></h2><p>Netty 项目不要只盯着“收到了什么消息”，更推荐从下面 4 个层面同时设计。</p><h3 id="_3-1-协议层" tabindex="-1">3.1 协议层 <a class="header-anchor" href="#_3-1-协议层" aria-label="Permalink to “3.1 协议层”">​</a></h3><p>你要先想清楚：</p><ul><li>消息边界怎么识别</li><li>是否有长度字段</li><li>有没有消息类型</li><li>有没有请求 ID</li><li>要不要版本号</li><li>要不要心跳包定义</li></ul><h3 id="_3-2-连接层" tabindex="-1">3.2 连接层 <a class="header-anchor" href="#_3-2-连接层" aria-label="Permalink to “3.2 连接层”">​</a></h3><p>你要先想清楚：</p><ul><li>长连接还是短连接</li><li>是否需要登录态绑定</li><li>空闲连接多久判定失效</li><li>异常断连后怎么清理资源</li><li>是否需要断线重连</li></ul><h3 id="_3-3-线程层" tabindex="-1">3.3 线程层 <a class="header-anchor" href="#_3-3-线程层" aria-label="Permalink to “3.3 线程层”">​</a></h3><p>你要先想清楚：</p><ul><li>I/O 线程只做什么</li><li>哪些耗时逻辑要下沉到业务线程池</li><li>线程池大小和队列如何控制</li><li>慢业务是否会拖垮 EventLoop</li></ul><h3 id="_3-4-资源层" tabindex="-1">3.4 资源层 <a class="header-anchor" href="#_3-4-资源层" aria-label="Permalink to “3.4 资源层”">​</a></h3><p>你要先想清楚：</p><ul><li>写缓冲是否会堆积</li><li>内存是否会持续上涨</li><li>对象创建是否过多</li><li>大包、坏包、恶意包如何限制</li></ul><p>这 4 层如果只设计 1 层，项目大概率能跑，但不太能稳。</p><hr><h2 id="_4-先看-3-类典型场景" tabindex="-1">4. 先看 3 类典型场景 <a class="header-anchor" href="#_4-先看-3-类典型场景" aria-label="Permalink to “4. 先看 3 类典型场景”">​</a></h2><p>Netty 常见落地场景可以先粗分为：</p><ul><li>RPC</li><li>IM</li><li>网关/代理</li></ul><p>虽然它们底层都用网络收发，但重点完全不一样。</p><h3 id="_4-1-rpc-场景更关注什么" tabindex="-1">4.1 RPC 场景更关注什么 <a class="header-anchor" href="#_4-1-rpc-场景更关注什么" aria-label="Permalink to “4.1 RPC 场景更关注什么”">​</a></h3><p>更关注：</p><ul><li>请求响应模型</li><li>请求 ID 匹配</li><li>超时控制</li><li>线程池隔离</li><li>编解码效率</li></ul><h3 id="_4-2-im-场景更关注什么" tabindex="-1">4.2 IM 场景更关注什么 <a class="header-anchor" href="#_4-2-im-场景更关注什么" aria-label="Permalink to “4.2 IM 场景更关注什么”">​</a></h3><p>更关注：</p><ul><li>长连接管理</li><li>心跳保活</li><li>在线状态</li><li>消息推送</li><li>断线重连</li></ul><h3 id="_4-3-网关场景更关注什么" tabindex="-1">4.3 网关场景更关注什么 <a class="header-anchor" href="#_4-3-网关场景更关注什么" aria-label="Permalink to “4.3 网关场景更关注什么”">​</a></h3><p>更关注：</p><ul><li>高并发连接</li><li>背压控制</li><li>路由转发</li><li>协议转换</li><li>限流与隔离</li></ul><p>这说明一件事：</p><ul><li><strong>Netty 只是底层能力，真正怎么设计，要看场景重点。</strong></li></ul><hr><h2 id="_5-实战时第一个问题-你的协议是否足够可用" tabindex="-1">5. 实战时第一个问题：你的协议是否足够可用 <a class="header-anchor" href="#_5-实战时第一个问题-你的协议是否足够可用" aria-label="Permalink to “5. 实战时第一个问题：你的协议是否足够可用”">​</a></h2><p>很多服务后面出问题，不是业务逻辑先崩，而是协议先不够用。</p><p>一个相对靠谱的最小协议，通常至少应该考虑：</p><ul><li>魔数</li><li>协议版本</li><li>消息类型</li><li>请求 ID</li><li>长度字段</li><li>消息体</li></ul><p>例如：</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>[魔数][版本][类型][请求ID][长度][消息体]</span></span></code></pre></div><p>为什么这些字段重要？</p><ul><li>魔数：快速识别协议</li><li>版本：支持后续演进</li><li>类型：区分请求、响应、心跳、通知</li><li>请求 ID：做异步请求响应关联</li><li>长度：解决边界问题</li></ul><p>如果协议连这些都没考虑，后面很容易在：</p><ul><li>扩展</li><li>排障</li><li>兼容</li></ul><p>上持续吃亏。</p><hr><h2 id="_6-第二个问题-连接策略怎么定" tabindex="-1">6. 第二个问题：连接策略怎么定 <a class="header-anchor" href="#_6-第二个问题-连接策略怎么定" aria-label="Permalink to “6. 第二个问题：连接策略怎么定”">​</a></h2><p>连接不是“连上就行”。</p><p>你要先想清楚这几个问题：</p><h3 id="_6-1-用长连接还是短连接" tabindex="-1">6.1 用长连接还是短连接 <a class="header-anchor" href="#_6-1-用长连接还是短连接" aria-label="Permalink to “6.1 用长连接还是短连接”">​</a></h3><p>大多数 Netty 项目更偏向长连接，因为：</p><ul><li>减少频繁建连开销</li><li>更适合持续通信</li><li>更适合状态维护</li></ul><p>但长连接带来的问题也要一起处理：</p><ul><li>心跳</li><li>空闲检测</li><li>断线回收</li><li>资源占用</li></ul><h3 id="_6-2-连接要不要绑定业务身份" tabindex="-1">6.2 连接要不要绑定业务身份 <a class="header-anchor" href="#_6-2-连接要不要绑定业务身份" aria-label="Permalink to “6.2 连接要不要绑定业务身份”">​</a></h3><p>例如 IM 场景里，连接往往会和：</p><ul><li>用户 ID</li><li>设备 ID</li><li>会话 ID</li></ul><p>绑定。</p><p>这样你后面才能做：</p><ul><li>定向推送</li><li>在线状态管理</li><li>重连恢复</li></ul><h3 id="_6-3-连接断了之后怎么办" tabindex="-1">6.3 连接断了之后怎么办 <a class="header-anchor" href="#_6-3-连接断了之后怎么办" aria-label="Permalink to “6.3 连接断了之后怎么办”">​</a></h3><p>必须提前定义策略：</p><ul><li>服务端是否主动清理资源</li><li>客户端是否自动重连</li><li>重连间隔如何退避</li><li>是否需要重新鉴权</li></ul><p>这类问题如果不提前设计，上线后就会变成到处补洞。</p><hr><h2 id="_7-第三个问题-心跳机制怎么做" tabindex="-1">7. 第三个问题：心跳机制怎么做 <a class="header-anchor" href="#_7-第三个问题-心跳机制怎么做" aria-label="Permalink to “7. 第三个问题：心跳机制怎么做”">​</a></h2><p>心跳是 Netty 实战中非常高频的一块。</p><h3 id="心跳主要解决什么" tabindex="-1">心跳主要解决什么 <a class="header-anchor" href="#心跳主要解决什么" aria-label="Permalink to “心跳主要解决什么”">​</a></h3><p>它主要不是为了“聊天”，而是为了：</p><ul><li>判断连接是否还活着</li><li>尽早发现断线、假死、网络异常</li><li>清理长期失效连接</li></ul><h3 id="为什么不能只靠-tcp-自己发现" tabindex="-1">为什么不能只靠 TCP 自己发现 <a class="header-anchor" href="#为什么不能只靠-tcp-自己发现" aria-label="Permalink to “为什么不能只靠 TCP 自己发现”">​</a></h3><p>因为很多场景里：</p><ul><li>连接物理上断了，但应用层感知不及时</li><li>网络中间设备可能让连接状态变得不稳定</li><li>你需要比系统默认更快地发现问题</li></ul><h3 id="典型思路" tabindex="-1">典型思路 <a class="header-anchor" href="#典型思路" aria-label="Permalink to “典型思路”">​</a></h3><p>通常会设计：</p><ul><li>客户端定时发心跳</li><li>服务端记录最后活跃时间</li><li>超过阈值未收到则关闭连接</li></ul><p>你也可以借助 Netty 的空闲检测处理器，例如：</p><ul><li><code>IdleStateHandler</code></li></ul><p>这会比手工管理省很多事。</p><hr><h2 id="_8-第四个问题-异常断连和资源清理" tabindex="-1">8. 第四个问题：异常断连和资源清理 <a class="header-anchor" href="#_8-第四个问题-异常断连和资源清理" aria-label="Permalink to “8. 第四个问题：异常断连和资源清理”">​</a></h2><p>很多 demo 的问题不是“断不了”，而是：</p><ul><li>断了以后没清干净</li></ul><p>例如：</p><ul><li>连接断了但用户在线状态没清</li><li><code>Channel</code> 从映射表里没移除</li><li>定时任务还在跑</li><li>缓存状态还保留着</li><li>重试逻辑继续往死连接写数据</li></ul><p>所以一条连接关闭时，通常要检查这些事：</p><ol><li>连接相关属性是否清理</li><li>用户/会话绑定是否解绑</li><li>订阅关系是否移除</li><li>定时任务是否取消</li><li>监控计数是否更新</li></ol><p>如果这些没处理好，问题就会从“断一次连接”变成“慢慢积累的脏状态”。</p><hr><h2 id="_9-第五个问题-背压怎么理解" tabindex="-1">9. 第五个问题：背压怎么理解 <a class="header-anchor" href="#_9-第五个问题-背压怎么理解" aria-label="Permalink to “9. 第五个问题：背压怎么理解”">​</a></h2><p>背压是很多人做到中后期才真正体会到的问题。</p><p>通俗理解就是：</p><ul><li><strong>你写得太快，但对方消费不过来。</strong></li></ul><p>结果可能是：</p><ul><li>写缓冲区持续堆积</li><li>内存上涨</li><li>延迟变大</li><li>最终把整个服务拖垮</li></ul><h3 id="常见场景" tabindex="-1">常见场景 <a class="header-anchor" href="#常见场景" aria-label="Permalink to “常见场景”">​</a></h3><p>例如服务端不断推送消息给客户端：</p><ul><li>客户端网络慢</li><li>客户端处理能力弱</li><li>服务端还在无节制写出</li></ul><p>这时候“能写”不等于“应该继续写”。</p><h3 id="你至少要建立的直觉" tabindex="-1">你至少要建立的直觉 <a class="header-anchor" href="#你至少要建立的直觉" aria-label="Permalink to “你至少要建立的直觉”">​</a></h3><ul><li>发送能力不是无限的</li><li>慢消费者会反过来拖累生产端</li></ul><p>所以实战里要关注：</p><ul><li>Channel 可写状态</li><li>写缓冲水位</li><li>降速或丢弃策略</li></ul><hr><h2 id="_10-第六个问题-线程与业务隔离" tabindex="-1">10. 第六个问题：线程与业务隔离 <a class="header-anchor" href="#_10-第六个问题-线程与业务隔离" aria-label="Permalink to “10. 第六个问题：线程与业务隔离”">​</a></h2><p>Netty 项目线上抖动，极高概率会和这件事相关。</p><p>如果你把下面这些都放在 I/O 线程里：</p><ul><li>慢查询</li><li>外部调用</li><li>复杂计算</li><li>批量处理</li></ul><p>那么后果不是只影响当前请求，而是可能影响整个 EventLoop 上一批连接。</p><p>更稳妥的做法通常是：</p><ul><li>I/O 线程负责协议处理、轻逻辑、投递任务</li><li>业务线程池负责真正耗时业务</li><li>对慢任务做超时、拒绝、熔断、隔离</li></ul><p>所以真正要避免的不是“代码复杂”，而是：</p><ul><li><strong>把局部慢任务放大成全局阻塞。</strong></li></ul><hr><h2 id="_11-第七个问题-排障时先看什么" tabindex="-1">11. 第七个问题：排障时先看什么 <a class="header-anchor" href="#_11-第七个问题-排障时先看什么" aria-label="Permalink to “11. 第七个问题：排障时先看什么”">​</a></h2><p>Netty 服务一出问题，不要上来就猜。</p><p>更推荐按层排：</p><h3 id="_11-1-先看连接层" tabindex="-1">11.1 先看连接层 <a class="header-anchor" href="#_11-1-先看连接层" aria-label="Permalink to “11.1 先看连接层”">​</a></h3><p>关注：</p><ul><li>连接数是否异常涨跌</li><li>是否大量频繁建连断连</li><li>心跳是否超时</li><li>是否某类连接集体掉线</li></ul><h3 id="_11-2-再看线程层" tabindex="-1">11.2 再看线程层 <a class="header-anchor" href="#_11-2-再看线程层" aria-label="Permalink to “11.2 再看线程层”">​</a></h3><p>关注：</p><ul><li>EventLoop 是否被堵</li><li>业务线程池是否堆积</li><li>是否有明显阻塞调用</li></ul><h3 id="_11-3-再看协议层" tabindex="-1">11.3 再看协议层 <a class="header-anchor" href="#_11-3-再看协议层" aria-label="Permalink to “11.3 再看协议层”">​</a></h3><p>关注：</p><ul><li>是否有粘包拆包解析异常</li><li>是否有长度字段错误</li><li>是否出现非法包、超大包</li><li>是否解码失败率上升</li></ul><h3 id="_11-4-再看资源层" tabindex="-1">11.4 再看资源层 <a class="header-anchor" href="#_11-4-再看资源层" aria-label="Permalink to “11.4 再看资源层”">​</a></h3><p>关注：</p><ul><li>内存是否上涨</li><li>GC 是否频繁</li><li>写缓冲是否堆积</li><li>是否存在 ByteBuf 泄漏</li></ul><h3 id="_11-5-最后看业务依赖层" tabindex="-1">11.5 最后看业务依赖层 <a class="header-anchor" href="#_11-5-最后看业务依赖层" aria-label="Permalink to “11.5 最后看业务依赖层”">​</a></h3><p>关注：</p><ul><li>下游数据库是否变慢</li><li>外部 RPC 是否超时</li><li>某类业务请求是否异常放大</li></ul><p>这个顺序的好处是：</p><ul><li>你会按链路定位，而不是凭感觉乱改参数</li></ul><hr><h2 id="_12-一个实战设计模板" tabindex="-1">12. 一个实战设计模板 <a class="header-anchor" href="#_12-一个实战设计模板" aria-label="Permalink to “12. 一个实战设计模板”">​</a></h2><p>如果你要设计一个最小可用的 Netty 服务，可以按下面这份清单过一遍。</p><h3 id="协议" tabindex="-1">协议 <a class="header-anchor" href="#协议" aria-label="Permalink to “协议”">​</a></h3><ul><li>是否有长度字段</li><li>是否有消息类型</li><li>是否有版本号</li><li>是否有请求 ID</li><li>是否限制最大包长</li></ul><h3 id="连接" tabindex="-1">连接 <a class="header-anchor" href="#连接" aria-label="Permalink to “连接”">​</a></h3><ul><li>长连接还是短连接</li><li>是否需要登录态绑定</li><li>心跳多久一次</li><li>空闲超时多久关闭</li><li>断连后是否重连</li></ul><h3 id="线程" tabindex="-1">线程 <a class="header-anchor" href="#线程" aria-label="Permalink to “线程”">​</a></h3><ul><li>I/O 线程只做什么</li><li>哪些逻辑下沉业务线程池</li><li>业务线程池如何限流和拒绝</li></ul><h3 id="稳定性" tabindex="-1">稳定性 <a class="header-anchor" href="#稳定性" aria-label="Permalink to “稳定性”">​</a></h3><ul><li>异常怎么记录</li><li>是否统一关闭异常连接</li><li>是否有背压处理</li><li>是否有慢消费者保护</li></ul><h3 id="监控" tabindex="-1">监控 <a class="header-anchor" href="#监控" aria-label="Permalink to “监控”">​</a></h3><ul><li>连接数</li><li>入站/出站 QPS</li><li>解码失败数</li><li>心跳超时数</li><li>线程池堆积</li><li>平均响应时间</li></ul><p>这份清单越早想清楚，后面越少返工。</p><hr><h2 id="_13-最容易踩的坑" tabindex="-1">13. 最容易踩的坑 <a class="header-anchor" href="#_13-最容易踩的坑" aria-label="Permalink to “13. 最容易踩的坑”">​</a></h2><h3 id="_13-1-demo-能跑就当设计完成" tabindex="-1">13.1 demo 能跑就当设计完成 <a class="header-anchor" href="#_13-1-demo-能跑就当设计完成" aria-label="Permalink to “13.1 demo 能跑就当设计完成”">​</a></h3><p>这是最常见误区。</p><h3 id="_13-2-没有心跳和空闲连接回收" tabindex="-1">13.2 没有心跳和空闲连接回收 <a class="header-anchor" href="#_13-2-没有心跳和空闲连接回收" aria-label="Permalink to “13.2 没有心跳和空闲连接回收”">​</a></h3><p>上线后很容易积累大量失效连接。</p><h3 id="_13-3-断连时没有完整清理资源" tabindex="-1">13.3 断连时没有完整清理资源 <a class="header-anchor" href="#_13-3-断连时没有完整清理资源" aria-label="Permalink to “13.3 断连时没有完整清理资源”">​</a></h3><p>会留下脏状态、内存占用和逻辑错乱。</p><h3 id="_13-4-不做背压控制" tabindex="-1">13.4 不做背压控制 <a class="header-anchor" href="#_13-4-不做背压控制" aria-label="Permalink to “13.4 不做背压控制”">​</a></h3><p>服务端越忙越拼命写，最后把自己拖死。</p><h3 id="_13-5-在-i-o-线程里做耗时业务" tabindex="-1">13.5 在 I/O 线程里做耗时业务 <a class="header-anchor" href="#_13-5-在-i-o-线程里做耗时业务" aria-label="Permalink to “13.5 在 I/O 线程里做耗时业务”">​</a></h3><p>这是最典型的性能和稳定性杀手。</p><h3 id="_13-6-出问题先改参数-不先定位链路" tabindex="-1">13.6 出问题先改参数，不先定位链路 <a class="header-anchor" href="#_13-6-出问题先改参数-不先定位链路" aria-label="Permalink to “13.6 出问题先改参数，不先定位链路”">​</a></h3><p>容易把本来局部的问题放大成更复杂的问题。</p><hr><h2 id="_14-动手建议" tabindex="-1">14. 动手建议 <a class="header-anchor" href="#_14-动手建议" aria-label="Permalink to “14. 动手建议”">​</a></h2><p>建议你至少做 3 个小练习。</p><h3 id="_14-1-设计一个最小-rpc-协议" tabindex="-1">14.1 设计一个最小 RPC 协议 <a class="header-anchor" href="#_14-1-设计一个最小-rpc-协议" aria-label="Permalink to “14.1 设计一个最小 RPC 协议”">​</a></h3><p>目标：</p><ul><li>练习长度字段、消息类型、请求 ID 的设计</li></ul><h3 id="_14-2-为一个长连接服务补上心跳和空闲关闭" tabindex="-1">14.2 为一个长连接服务补上心跳和空闲关闭 <a class="header-anchor" href="#_14-2-为一个长连接服务补上心跳和空闲关闭" aria-label="Permalink to “14.2 为一个长连接服务补上心跳和空闲关闭”">​</a></h3><p>目标：</p><ul><li>建立连接管理意识</li></ul><h3 id="_14-3-做一份-netty-排障清单" tabindex="-1">14.3 做一份 Netty 排障清单 <a class="header-anchor" href="#_14-3-做一份-netty-排障清单" aria-label="Permalink to “14.3 做一份 Netty 排障清单”">​</a></h3><p>目标：</p><ul><li>把“出问题时先看什么”固定成套路，而不是靠临场想</li></ul><hr><h2 id="_15-自测问题" tabindex="-1">15. 自测问题 <a class="header-anchor" href="#_15-自测问题" aria-label="Permalink to “15. 自测问题”">​</a></h2><ul><li>为什么 Netty 项目最终一定会遇到“稳定性设计”问题，而不是只要能收发消息就够了？</li><li>心跳机制主要解决什么问题？</li><li>为什么异常断连后必须做完整资源清理？</li><li>背压在 Netty 场景里通常意味着什么？</li><li>排查 Netty 故障时，为什么要按连接、线程、协议、资源、业务依赖分层看？</li></ul><hr><h2 id="_16-这一章你至少要带走什么" tabindex="-1">16. 这一章你至少要带走什么 <a class="header-anchor" href="#_16-这一章你至少要带走什么" aria-label="Permalink to “16. 这一章你至少要带走什么”">​</a></h2><p>如果你看完这一章只记住 5 件事，就记下面这 5 件：</p><ol><li><strong>Netty 实战不是只写收发逻辑，而是要把协议、连接、线程、资源一起设计</strong></li><li><strong>心跳、空闲回收、断连清理，是长连接服务的基本功</strong></li><li><strong>背压控制决定了服务在高流量下会不会被慢消费者拖垮</strong></li><li><strong>I/O 线程和耗时业务必须尽量隔离</strong></li><li><strong>排障要按链路分层看，别凭感觉乱改参数</strong></li></ol><p>把这几个点建立起来后，你看 Netty 就不会停留在“一个网络框架”，而会开始把它当成一套真正可落地的网络服务底座。</p>',201)])])}const b=i(h,[["render",t]]);export{u as __pageData,b as default};
